 1	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	
 5	export enum TruncateLength {
 6	  OFF = 0,
 7	  XS = 10,
 8	  S = 20,
 9	  M = 25,
10	  L = 30,
11	  XL = 40
12	}
13	
14	export interface TruncateDropdownProps {
15	  selected: TruncateLength;
16	  setTruncateLength: (v: TruncateLength) => void;
17	  id?: string;
18	}
19	
20	export const TruncateDropdown: React.FC<TruncateDropdownProps> = ({ selected, setTruncateLength, id }) => {
21	  const { t } = useTranslation('plugin__netobserv-plugin');
22	  const [isOpen, setOpen] = React.useState(false);
23	
24	  const getTruncateDisplay = (v: TruncateLength) => {
25	    switch (v) {
26	      case TruncateLength.XL:
27	        return t('XL');
28	      case TruncateLength.L:
29	        return t('L');
30	      case TruncateLength.M:
31	        return t('M');
32	      case TruncateLength.S:
33	        return t('S');
34	      case TruncateLength.XS:
35	        return t('XS');
36	      default:
37	        return t('None');
38	    }
39	  };
40	
41	  return (
42	    <Dropdown
43	      data-test={id}
44	      id={id}
45	      isOpen={isOpen}
46	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
47	        <MenuToggle
48	          ref={toggleRef}
49	          data-test={`${id}-dropdown`}
50	          id={`${id}-dropdown`}
51	          isExpanded={isOpen}
52	          onClick={() => setOpen(!isOpen)}
53	          onBlur={() => setTimeout(() => setOpen(false), 500)}
54	        >
55	          {getTruncateDisplay(selected)}
56	        </MenuToggle>
57	      )}
58	    >
59	      {[
60	        TruncateLength.OFF,
61	        TruncateLength.XS,
62	        TruncateLength.S,
63	        TruncateLength.M,
64	        TruncateLength.L,
65	        TruncateLength.XL
66	      ].map((v: TruncateLength) => (
67	        <DropdownItem
68	          data-test={String(v)}
69	          id={String(v)}
70	          key={v}
71	          onClick={() => {
72	            setOpen(false);
73	            setTruncateLength(v);
74	          }}
75	        >
76	          {getTruncateDisplay(v)}
77	        </DropdownItem>
78	      ))}
79	    </Dropdown>
80	  );
81	};
82	
83	export default TruncateDropdown;

