 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { TruncateDropdown, TruncateLength } from '../truncate-dropdown';
 6	
 7	describe('<TruncateDropdown />', () => {
 8	  const props = {
 9	    selected: TruncateLength.M,
10	    setTruncateLength: jest.fn(),
11	    id: 'truncate'
12	  };
13	
14	  it('should render component', async () => {
15	    render(<TruncateDropdown {...props} />);
16	    expect(screen.getByRole('button')).toHaveAttribute('id', 'truncate-dropdown');
17	  });
18	
19	  it('should open and close', async () => {
20	    const { container } = render(<TruncateDropdown {...props} />);
21	
22	    await act(async () => {
23	      fireEvent.click(container.querySelector('#truncate-dropdown')!);
24	    });
25	    await waitFor(() => {
26	      expect(document.querySelectorAll('[data-test="truncate"] li').length).toBeGreaterThan(0);
27	    });
28	
29	    await act(async () => {
30	      fireEvent.click(container.querySelector('#truncate-dropdown')!);
31	    });
32	
33	    expect(props.setTruncateLength).toHaveBeenCalledTimes(0);
34	  });
35	
36	  it('should refresh on select', async () => {
37	    const user = userEvent.setup();
38	    const { container } = render(<TruncateDropdown {...props} />);
39	
40	    await act(async () => {
41	      fireEvent.click(container.querySelector('#truncate-dropdown')!);
42	    });
43	    await waitFor(() => expect(document.querySelector('[id="0"]')).toBeTruthy());
44	
45	    await user.click(document.querySelector('[id="0"]')!);
46	    expect(props.setTruncateLength).toHaveBeenCalledWith(TruncateLength.OFF);
47	
48	    await act(async () => {
49	      fireEvent.click(container.querySelector('#truncate-dropdown')!);
50	    });
51	    await waitFor(() => expect(document.querySelector('[id="40"]')).toBeTruthy());
52	
53	    await user.click(document.querySelector('[id="40"]')!);
54	
55	    expect(props.setTruncateLength).toHaveBeenCalledTimes(2);
56	    expect(props.setTruncateLength).toHaveBeenCalledWith(TruncateLength.XL);
57	  });
58	});

